INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('dietitian-moex-10624', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關生長激素對於代謝的調節之敘述，何者不正確？ 可增加細胞攝取胺基酸的能力，促進蛋白質的合成 可減少細胞攝取葡萄糖的能力，節省醣類的消耗量 可使脂肪氧化分解，以產生能量 可促進酮體的有效利用，以減少組織蛋白質的分解', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 9, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10625', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何者為非屬於多醣類的膳食纖維質，而為苯丙醇和苯丙酸之複合體，具膳食纖維質之功用？ Gum  Lignan  Pectin  Lignin', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 10, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10626', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關膽固醇之敘述，何者不正確？ 膽固醇主要存在於動物性細胞中，其由五個環狀構造及一條長的碳鏈組成 膽固醇可合成腎上腺皮質激素和性激素 在紫外光的照射下，7-去氫膽固醇可轉變成維生素D 3 膽固醇可代謝為膽酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 11, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10627', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關必需脂肪酸的敘述，何者不正確？ 人體可利用亞麻油酸合成花生油烯酸（Arachidonic acid），故後者非為必需脂肪酸 必需脂肪酸是細胞膜與脂蛋白的重要成分 必需脂肪酸可在體內轉變為不同型式之前列腺素 人體可利用必需脂肪酸合成膽酸', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 12, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10628', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '膳食纖維質降低血清膽固醇之作用，下列敘述何者不正確？ 與膽酸結合，增加膽酸的排泄 吸水成為膠狀包圍膽固醇，減少其吸收 促進腸管蠕動增加膽固醇之排泄 為腸道細菌發酵為短鏈脂肪酸，抑制膽酸之再吸收', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10629', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關基礎代謝率（BMR）之敘述，何者不正確？ 體表面積越大的人，散熱越多。故一個矮胖的人比同年齡、同性別瘦高者的BMR會較高 女性的BMR一般較男性低，因女性的脂肪組織較男性多 運動家的細胞質組織較多，故BMR較高 營養不良的人其BMR較低', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10630', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '某一男子，現在體重70公斤，若一天少吃500大卡，則一星期約可減少多少體重？', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10631', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '5 lb  0.5 kg  1 lb  1 kg', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 0, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10632', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列那一種酵素非以維生素B 作為其輔酵素？ 2 Lactic dehydrogenase    Xanthine oxidase Glucose-6-phosphate dehydrogenase  L-amino acid dehydrogenase', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10633', 'dietitian', 'dietitian-moex-094-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '菸鹼素的需要量隨熱量攝取量而定，若某人一日之熱量攝取量為2500大卡，則其菸鹼素之需要量約為：', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:56+00:00", "source_pdf_sha1": "de86e5e3c8c3", "answer_pdf_sha1": "794bf55cd1a4", "source_family": "moex-gov-tw", "moex": {"exam_code": "094020", "c": "112", "s": "2001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "營養學", "year": "094", "exam_name": "094年第一次專技醫事人員、中醫師、心理師、呼吸治療師、營養師、獸醫人員考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
